var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"좋아. 그렇게 하자.","JPN":" わかった、そうしよう。","ENG":"Very well. Let's do that.","TWN":" 好，就這麼辦吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…음?","JPN":"……ん？","ENG":"...Mm?","TWN":"…嗯？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"후후, 무슨 얼빠진 표정이람? 너무 고민 없이 승낙해버려서 시시해진 거야?","JPN":"ふふ、何て間抜けな顔をしてるんだ？　あまりにもすんなりと承諾するから気が抜けたのか？","ENG":"Fu fuu. What kind of stupid expression is that? Are you bored because I agreed without hesitation?","TWN":"呵呵，那是什麼一臉失落的表情？因為我答應得太快，你覺得很沒意思嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"전문은 확인했어. 사장과 직원으로서, 당신이 날 부려먹어도 상관없다는 뜻이야.","JPN":"すべて確認した。社長と職員として、君が私をこき使っても構わないという意味だ。","ENG":"I've read everything in detail. I'm telling you that I do not mind being bossed around as your employee.","TWN":"契約內容我已經看過，我們是老闆和員工的關係，也就是你可以任意使喚我的意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"궁금했거든. 당신이 날 마음대로 부리게 됐을 때 어떤 태도를 보여줄지.","JPN":"気になっていたんだ。君が私を自分の思い通りに動かすようになった時、どんな態度を見せてくれるのか。","ENG":"I was curious to see what attitude you would have toward me once you had me at your mercy.","TWN":"我很好奇，當你任意使喚我時，會是用什麼樣的態度。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"다만, 내게 진심 어린 충성 같은 걸 기대하진 마.","JPN":"だが、私に忠誠のようなものは期待するな。","ENG":"However, don't expect me to be truly loyal to you.","TWN":"但醜話說在前頭，你可別期待我會真心對你效忠。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"난 분명 당신의 어떤 지시든 따를 테고, 그건 날 따르는 부하들도 마찬가지겠지만… 이 실험에 사적인 감정 같은 변수를 둘 생각은 없으니까.","JPN":"私はおそらく君のどんな指示にも従うだろうし、それは私に従う部下たちも同じだろう……この実験に私情のような変数を挟むつもりはないから。","ENG":"I will obey any order you give me, and so will my subordinates... but I have no intention of allowing variables such as personal emotions in this experiment.","TWN":"我會完全聽從你的任何指示，我的部下也是如此…但我不打算讓私人的情感成為這場實驗中的變數。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"…그래, 실험이야.","JPN":"……そうだ、実験だ。","ENG":"...Yes, it's an experiment.","TWN":"…沒錯，這就只是實驗而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"난 당신을 오래전부터 연구하고 싶었어.","JPN":"私は君をずっと前から研究したかった。","ENG":"I've always wanted to study you.","TWN":"我很久以前就想好好研究你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"당신이 정확히 어떤 존재인지. 인류가 기로에 섰을 때 어떤 결정을 내릴지.","JPN":"君が正確にどんな存在なのか。人類が岐路に立たされた時、どのような決断を下すのか。","ENG":"I want to know what you are and what decisions you will make when humanity reaches a crossroads.","TWN":"你到底是何方神聖，當人類佇立在交叉口時，你會做出什麼決定。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"곁에서 이 두 눈으로 관찰하고 싶어.","JPN":"そばにいながらこの目で観察したい。","ENG":"I want to observe you as closely as I can with my own eyes.","TWN":"我要在你身旁，用我這雙眼睛仔細觀察。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"이런 관계라도 괜찮다면, 최종 결정은 당신에게 맡길게.","JPN":"こんな関係でよければ、最終決定は君に任せる。","ENG":"If you're still fine with this kind of relationship, I'll leave the final decision to you.","TWN":"你不介意我們是這種關係的話，那我要把最終決定權交給你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};